/**
 * Notification model — core types for the notification system.
 *
 * All notifications flow through the EventBus. Services emit domain events
 * (e.g., order:created), the NotificationService listens and dispatches
 * through registered NotificationAdapters (email, webhook, SMS, etc.).
 */

/**
 * Supported notification types. Each maps to a specific domain event
 * that triggers a notification.
 */
export type NotificationType =
  | 'order_confirmation'
  | 'order_status_update'
  | 'user_welcome'
  | 'user_updated';

/**
 * Delivery channels for notifications. Each channel has a corresponding
 * adapter that implements NotificationAdapter.
 */
export type NotificationChannel = 'email' | 'webhook' | 'sms' | 'in_app';

/**
 * The payload passed to notification adapters for delivery.
 * Adapters receive this and handle channel-specific formatting/sending.
 */
export interface NotificationPayload {
  id: string;
  type: NotificationType;
  channel: NotificationChannel;
  recipient: string;
  subject: string;
  body: string;
  metadata: Record<string, unknown>;
  createdAt: Date;
}

/**
 * Result returned by adapters after attempting delivery.
 */
export interface NotificationResult {
  success: boolean;
  channel: NotificationChannel;
  recipient: string;
  error?: string;
  deliveredAt?: Date;
}

/**
 * A persisted notification record, including delivery status.
 */
export interface Notification {
  id: string;
  type: NotificationType;
  channel: NotificationChannel;
  recipient: string;
  subject: string;
  body: string;
  metadata: Record<string, unknown>;
  status: 'pending' | 'sent' | 'failed';
  createdAt: Date;
  sentAt?: Date;
  error?: string;
}

/**
 * Email notification adapter — delivers notifications via email.
 *
 * This is a stub implementation that logs emails instead of sending them.
 * A real implementation would integrate with an SMTP service or email API
 * (e.g., SendGrid, AWS SES, Postmark).
 *
 * Implements NotificationAdapter interface.
 */

import type { NotificationAdapter } from './notification.adapter.js';
import type { NotificationChannel, NotificationPayload, NotificationResult } from '../models/notification.js';
import { Logger } from '../utils/logger.js';

export interface EmailConfig {
  from: string;
  replyTo?: string;
}

const defaultEmailConfig: EmailConfig = {
  from: 'noreply@taskflowpro.com',
};

export class EmailAdapter implements NotificationAdapter {
  readonly channel: NotificationChannel = 'email';
  private logger = new Logger('EmailAdapter');
  private sentEmails: NotificationPayload[] = [];

  constructor(private config: EmailConfig = defaultEmailConfig) {}

  /**
   * Send an email notification.
   * Stub: logs the email and stores it in-memory for testing.
   */
  async send(payload: NotificationPayload): Promise<NotificationResult> {
    this.logger.info(
      `Sending email to ${payload.recipient}: ${payload.subject}`,
    );

    try {
      // Stub: In production, this would call an email API.
      // For now, store in memory for testing/verification.
      this.sentEmails.push(payload);

      this.logger.info(
        `Email delivered to ${payload.recipient} (from: ${this.config.from})`,
      );

      return {
        success: true,
        channel: 'email',
        recipient: payload.recipient,
        deliveredAt: new Date(),
      };
    } catch (err) {
      const message = err instanceof Error ? err.message : 'Unknown email error';
      this.logger.error(`Email delivery failed: ${message}`);

      return {
        success: false,
        channel: 'email',
        recipient: payload.recipient,
        error: message,
      };
    }
  }

  /**
   * Get all sent emails. Useful for testing.
   */
  getSentEmails(): NotificationPayload[] {
    return [...this.sentEmails];
  }

  /**
   * Clear sent emails. Useful for testing.
   */
  clearSentEmails(): void {
    this.sentEmails = [];
  }
}

