parameters.content:
/**
 * Notification service — handles sending notifications in response to domain events.
 *
 * Architecture: Event-driven via EventBus.
 * - Services emit domain events (order:created, order:status-changed, etc.)
 * - NotificationService subscribes to these events
 * - Notifications are dispatched through registered NotificationAdapters
 *
 * All notifications flow through this service. Adapters handle channel-specific
 * delivery (email, webhook, SMS, etc.). To add a new channel, implement
 * NotificationAdapter and register it with this service.
 *
 * Constraints:
 * - All notification delivery MUST go through registered adapters
 * - All event subscriptions use EventBus (no CallbackRegistry)
 * - Adapters are registered at construction time and must not be modified after
 * - Each channel can have at most one adapter
 *
 * Depends on:
 * - EventBus (event system) for receiving domain events
 * - NotificationAdapter implementations for delivery
 */

import type { EventBus } from '../events/event-bus.js';
import type { OrderCreatedEvent, OrderStatusChangedEvent, UserCreatedEvent } from '../events/event-types.js';
import type { NotificationAdapter } from '../adapters/notification.adapter.js';
import type {
  Notification,
  NotificationChannel,
  NotificationPayload,
  NotificationType,
} from '../models/notification.js';
import { Logger } from '../utils/logger.js';

let nextId = 1;

function generateNotificationId(): string {
  return `notif-${String(nextId++).padStart(4, '0')}`;
}

export function resetNotificationIdCounter(): void {
  nextId = 1;
}

export class NotificationService {
  private logger = new Logger('NotificationService');
  private notifications: Notification[] = [];
  private adapters: Map<NotificationChannel, NotificationAdapter> = new Map();

  constructor(private eventBus: EventBus) {
    this.registerEventHandlers();
  }

  /**
   * Register a notification adapter for a specific channel.
   * Each channel can have at most one adapter.
   */
  registerAdapter(adapter: NotificationAdapter): void {
    if (this.adapters.has(adapter.channel)) {
      throw new Error(`Adapter already registered for channel: ${adapter.channel}`);
    }
    this.adapters.set(adapter.channel, adapter);
    this.logger.info(`Registered adapter for channel: ${adapter.channel}`);
  }

  /**
   * Get the adapter for a given channel, if registered.
   */
  getAdapter(channel: NotificationChannel): NotificationAdapter | undefined {
    return this.adapters.get(channel);
  }

  /**
   * Subscribe to domain events on the EventBus.
   * All event-driven notification triggers are registered here.
   */
  private registerEventHandlers(): void {
    this.eventBus.on<OrderCreatedEvent>('order:created', (event) => {
      this.handleOrderCreated(event);
    });

    this.eventBus.on<OrderStatusChangedEvent>('order:status-changed', (event) => {
      this.handleOrderStatusChanged(event);
    });

    this.eventBus.on<UserCreatedEvent>('user:created', (event) => {
      this.handleUserCreated(event);
    });
  }

  /**
   * Handle order created event — send confirmation notification.
   */
  private handleOrderCreated(event: OrderCreatedEvent): void {
    this.logger.info(`Sending order confirmation for order ${event.order.id}`);

    const itemSummary = event.order.items
      .map((item) => `${item.name} x${item.quantity}`)
      .join(', ');

    this.dispatchNotification({
      type: 'order_confirmation',
      channel: 'email',
      recipient: event.user.email,
      subject: `Order Confirmation: ${event.order.id}`,
      body: `Your order has been placed. Items: ${itemSummary}. Total: $${event.order.total.toFixed(2)}`,
      metadata: { orderId: event.order.id, userId: event.user.id },
    });
  }

  /**
   * Handle order status change — notify user of update.
   */
  private handleOrderStatusChanged(event: OrderStatusChangedEvent): void {
    this.logger.info(
      `Sending status update for order ${event.order.id}: ${event.previousStatus} -> ${event.newStatus}`,
    );

    this.dispatchNotification({
      type: 'order_status_update',
      channel: 'email',
      recipient: event.order.userId,
      subject: `Order Update: ${event.order.id}`,
      body: `Your order status has changed from ${event.previousStatus} to ${event.newStatus}.`,
      metadata: {
        orderId: event.order.id,
        previousStatus: event.previousStatus,
        newStatus: event.newStatus,
      },
    });
  }

  /**
   * Handle user created event — send welcome notification.
   */
  private handleUserCreated(event: UserCreatedEvent): void {
    this.logger.info(`Sending welcome notification for user ${event.user.id}`);

    this.dispatchNotification({
      type: 'user_welcome',
      channel: 'email',
      recipient: event.user.email,
      subject: 'Welcome to TaskFlow Pro!',
      body: `Hi ${event.user.name}, welcome to TaskFlow Pro. Your account has been created.`,
      metadata: { userId: event.user.id },
    });
  }

  /**
   * Dispatch a notification through the appropriate adapter.
   * If no adapter is registered for the channel, the notification is stored
   * with 'pending' status (useful for in-app notifications or deferred delivery).
   */
  private dispatchNotification(params: {
    type: NotificationType;
    channel: NotificationChannel;
    recipient: string;
    subject: string;
    body: string;
    metadata: Record<string, unknown>;
  }): void {
    const notification: Notification = {
      id: generateNotificationId(),
      type: params.type,
      channel: params.channel,
      recipient: params.recipient,
      subject: params.subject,
      body: params.body,
      metadata: params.metadata,
      status: 'pending',
      createdAt: new Date(),
    };

    const adapter = this.adapters.get(params.channel);
    if (adapter) {
      adapter.send({
        id: notification.id,
        type: notification.type,
        channel: notification.channel,
        recipient: notification.recipient,
        subject: notification.subject,
        body: notification.body,
        metadata: notification.metadata,
        createdAt: notification.createdAt,
      }).then((result) => {
        if (result.success) {
          notification.status = 'sent';
          notification.sentAt = result.deliveredAt;
          this.eventBus.emit({
            type: 'notification:sent',
            notification: { ...notification },
            timestamp: new Date(),
          });
        } else {
          notification.status = 'failed';
          notification.error = result.error;
          this.eventBus.emit({
            type: 'notification:failed',
            notification: { ...notification },
            error: result.error ?? 'Unknown error',
            timestamp: new Date(),
          });
        }
      });
    }

    this.notifications.push(notification);
    this.logger.info(`Notification ${notification.id} dispatched to ${params.recipient}`);
  }

  /**
   * Get all notifications.
   */
  getNotifications(): Notification[] {
    return [...this.notifications];
  }

  /**
   * Get notifications for a specific recipient.
   */
  getNotificationsForRecipient(recipient: string): Notification[] {
    return this.notifications.filter((n) => n.recipient === recipient);
  }

  /**
   * Get the count of notifications.
   */
  getNotificationCount(): number {
    return this.notifications.length;
  }

  /**
   * Clear all notifications (useful for testing).
   */
  clearNotifications(): void {
    this.notifications = [];
  }
}

