+/**
+ * Notification model — core types for the notification system.
+ *
+ * All notifications flow through the EventBus. Services emit domain events
+ * (e.g., order:created), the NotificationService listens and dispatches
+ * through registered NotificationAdapters (email, webhook, SMS, etc.).
+ */
+
+/**
+ * Supported notification types. Each maps to a specific domain event
+ * that triggers a notification.
+ */
+export type NotificationType =
+  | 'order_confirmation'
+  | 'order_status_update'
+  | 'user_welcome'
+  | 'user_updated';
+
+/**
+ * Delivery channels for notifications. Each channel has a corresponding
+ * adapter that implements NotificationAdapter.
+ */
+export type NotificationChannel = 'email' | 'webhook' | 'sms' | 'in_app';
+
+/**
+ * The payload passed to notification adapters for delivery.
+ * Adapters receive this and handle channel-specific formatting/sending.
+ */
+export interface NotificationPayload {
+  id: string;
+  type: NotificationType;
+  channel: NotificationChannel;
+  recipient: string;
+  subject: string;
+  body: string;
+  metadata: Record<string, unknown>;
+  createdAt: Date;
+}
+
+/**
+ * Result returned by adapters after attempting delivery.
+ */
+export interface NotificationResult {
+  success: boolean;
+  channel: NotificationChannel;
+  recipient: string;
+  error?: string;
+  deliveredAt?: Date;
+}
+
+/**
+ * A persisted notification record, including delivery status.
+ */
+export interface Notification {
+  id: string;
+  type: NotificationType;
+  channel: NotificationChannel;
+  recipient: string;
+  subject: string;
+  body: string;
+  metadata: Record<string, unknown>;
+  status: 'pending' | 'sent' | 'failed';
+  createdAt: Date;
+  sentAt?: Date;
+  error?: string;
+}

